/**
 * @summary Get spending breakdown by category for a month
 */
export const getGetCategorySummaryUrl = (params?: GetCategorySummaryParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/summary/categories?${stringifiedParams}`
    : `/api/summary/categories`;
};

export const getCategorySummary = async (
  params?: GetCategorySummaryParams,
  options?: RequestInit,
): Promise<CategorySummary[]> => {
  return customFetch<CategorySummary[]>(getGetCategorySummaryUrl(params), {
    ...options,
    method: "GET",
  });
};

